+import { join, resolve } from "@std/path";
+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths ?? [currentDirectory()];
+  const formats = options.formats ?? [".json", ".rc"];
+  const matches: Array<{ path: string; format: string }> = [];
+  for (const searchPath of paths) {
+    for (const format of formats) {
+      const path = resolve(searchPath, format === ".rc" ? `.${options.name}rc` : `${options.name}${format}`);
+      if (await exists(path)) matches.push({ path, format });
+    }
+  }
+  if (!matches.length) return { values: {} };
+  const selected = options.mergeConfigs ? matches : [matches[0]];
+  // Later files only fill keys that have not already been supplied by an earlier path.
+  const values: Record<string, unknown> = {};
+  for (const match of selected) {
+    let parsed: Record<string, unknown>;
+    try {
+      const content = await readTextFile(match.path);
+      parsed = options.parser ? options.parser(content) : match.format === ".json"
+        ? JSON.parse(content)
+        : parseRc(content);
+      if (!isPlainObject(parsed)) throw new Error("Configuration must contain an object.");
+    } catch (error) {
+      throw new ConfigParseError(match.path, error);
+    }
+    fillMissing(values, flatten(parsed));
+  }
+  return { path: selected[0].path, values };
+}
+
+export function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const index = trimmed.indexOf("=");
+    if (index < 1) throw new Error(`Invalid RC line "${line}".`);
+    const key = trimmed.slice(0, index).trim();
+    let value = trimmed.slice(index + 1).trim();
+    if (value.startsWith('"') && value.endsWith('"') && value.length >= 2) value = value.slice(1, -1);
+    result[key] = value === "true" ? true : value === "false" ? false : value !== "" && !Number.isNaN(Number(value)) ? Number(value) : value;
+  }
+  return result;
+}
+
+export function flatten(value: Record<string, unknown>, prefix = ""): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, child] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${camelCase(key)}` : camelCase(key);
+    if (isPlainObject(child)) Object.assign(result, flatten(child, name));
+    else result[name] = child;
+  }
+  return result;
+}
+
+function fillMissing(target: Record<string, unknown>, source: Record<string, unknown>) {
+  for (const [key, value] of Object.entries(source)) if (!(key in target)) target[key] = value;
+}
+function camelCase(value: string) { return value.replace(/-([a-zA-Z0-9])/g, (_, char) => char.toUpperCase()); }
+function isPlainObject(value: unknown): value is Record<string, unknown> { return !!value && typeof value === "object" && !Array.isArray(value) && Object.getPrototypeOf(value) === Object.prototype; }
